def should_filter(vod_name):
    """判断是否应该过滤该视频"""
    if not vod_name:
        return False
    
    # 精确匹配
    if vod_name in EXACT_FILTER_NAMES:
        return True
    
    # 关键词模糊匹配
    for keyword in FILTER_KEYWORDS:
        if keyword in vod_name:
            return True
    
    return False

def filter_video_list(video_list):
    """过滤视频列表"""
    if not video_list:
        return video_list
    
    filtered_list = []
    filtered_count = 0
    
    for item in video_list:
        vod_name = item.get('vod_name', '')
        if not should_filter(vod_name):
            filtered_list.append(item)
        else:
            filtered_count += 1
            print(f"[过滤] 已屏蔽: {vod_name}")
    
    if filtered_count > 0:
        print(f"[过滤] 共屏蔽 {filtered_count} 个视频")
    
    return filtered_list

# 重写 homeVideoContent 方法
def new_homeVideoContent(self):
    result = _original_homeVideoContent(self)
    if 'list' in result:
        result['list'] = filter_video_list(result['list'])
    return result

# 重写 categoryContent 方法
def new_categoryContent(self, tid, pg, filter, extend):
    result = _original_categoryContent(self, tid, pg, filter, extend)
    if 'list' in result:
        result['list'] = filter_video_list(result['list'])
    return result

# 重写 searchContent 方法
def new_searchContent(self, key, quick, pg="1"):
    result = _original_searchContent(self, key, quick, pg)
    if 'list' in result:
        result['list'] = filter_video_list(result['list'])
    return result

# 应用猴子补丁
Spider.homeVideoContent = new_homeVideoContent
Spider.categoryContent = new_categoryContent
Spider.searchContent = new_searchContent

